#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    float1 d = 0.005;
    float1 dx = ( 2*GetBlur2(vUv + vec2(d,0)) - 2*GetBlur2(vUv-vec2(d,0)) ).x*0.5;
    float1 dy = ( 2*GetBlur2(vUv + vec2(0,d)) - 2*GetBlur2(vUv-vec2(0,d)) ).x*0.5;
    float1 dxb = ( 2*GetBlur2(vUv + vec2(d,0)) - 2*GetBlur2(vUv-vec2(d,0)) ).x*0.5;
    float1 dyb = ( 2*GetBlur2(vUv + vec2(0,d)) - 2*GetBlur2(vUv-vec2(0,d)) ).x*0.5;
    vec2 my_uv = vUv - vec2(dx,dy)*0.005 + vec2(dxb,dyb)*0.002;



    vec2 v = 0.01;
    ret.x = texture( sampler_fc_main, my_uv).x;


    ret.x += (2*ret.x - 2*GetBlur3(vUv).x)*.05;
    ret.x += 0.006;

    ret.x = mix( ret.x, lum(ret).x, 0);

//--------------------------------

    my_uv = vUv + vec2(dy,-dx)*0.025*(2.4-2*GetBlur3(vUv).y);



    v = 0.01;
    ret.z = texture( sampler_fw_main, my_uv).z;


    ret.z += (2*ret.z - 2*GetBlur1(vUv).z)*length(my_uv-vUv)*60;
    ret.z *= 0.85;
    ret.z += 0.008;



//--------------------------------

    d = 0.01;
    my_uv = vec2(-dy,dx)*0.05;

    dx = ( 2*GetBlur2(vUv + vec2(d,0)) - 2*GetBlur2(vUv-vec2(d,0)) ).y*0.5;
    dy = ( 2*GetBlur2(vUv + vec2(0,d)) - 2*GetBlur2(vUv-vec2(0,d)) ).y*0.5;
    my_uv += vUv - vec2(dx,dy)*0.03;



    v = 0.01;
    ret.y =texture( sampler_fw_main, my_uv).y;


    ret.y += (2*ret.y - 2*GetBlur3(my_uv).y)*0.05 + 0.03;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uvo = vUv;
vUv = 0.5 + (vUv-0.5)*1.5;
vec2 rotate_uv = 0.5+uv_rotate(0 + (vUv-0.5)*uAspect.xy, 0, q3, q4, 2);
vec2 bipolar_uv = uv_bipolar(rotate_uv,vec2(0,0.5),vec2(1,0.5), 2, 0.35, vec2(q11,q12));
vec2 mirror_uv = 0.5 + (0.5 - abs( fract( bipolar_uv * 0.5 ) * 2.0 - 1.0 ));

vUv = mirror_uv;
    vec2 d = uTexSize.zw;
    vec3 dx = ( GetPixel(vUv+vec2(1,0)*d)-GetPixel(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetPixel(vUv+vec2(0,1)*d)-GetPixel(vUv-vec2(0,1)*d) );
vec2 dz = vec2(dx.y,dy.y)*3;

d = uTexSize.zw*2;
dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) );
dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) );

dz +=vec2(dx.y,dy.y);

vec3 bg = pow(length(dz)*0.8+0,0.7) + GetBlur2(vUv).y*0.4-0.1;

ret = bg*vec3(0.3,0.5,0.7);
ret = mix(ret,vec3(0.2,0.1,0),GetPixel(vUv + vec2(dx.x,dy.x)*uTexSize.zw*18).x*6);
ret = mix(ret,1,GetPixel(vUv).z);

//ret = GetPixel(vUv);

  fragColor = ret;
}
